// C++ Example
#include <iostream>
#include <vector>
#include <algorithm>

std::string greet(std::string name) {
    return "Hello, " + name + "!";
}

int main() {
    std::cout << greet("Dolores") << std::endl;
    std::vector<int> nums = {1,2,3,4,5};
    std::transform(nums.begin(),nums.end(),nums.begin(),[](int n){return n*2;});
    for(int n:nums) std::cout << n << " ";
    std::cout << std::endl;
    return 0;
}
